var builder = WebApplication.CreateBuilder(args);

// [Fix 4] ValidateOnBuild/ValidateScopes now enabled in Development by default.
// A scoped IUserService captured inside a singleton factory will throw
// InvalidOperationException at startup. Register CacheService as scoped instead.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// [Fix 1] HttpClientFactory now uses SocketsHttpHandler by default.
// Casting to HttpClientHandler throws InvalidCastException at runtime.
// Use ConfigurePrimaryHttpMessageHandler with the desired handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// [Fix 2] Forwarded Headers Middleware now ignores X-Forwarded-* headers
// from unknown proxies. Add your reverse proxy to KnownProxies or KnownNetworks.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // TODO: Replace with your actual reverse proxy address(es)
    options.KnownProxies.Add(System.Net.IPAddress.Parse("10.0.0.1"));
});

// [Fix 3] HttpClientFactory Trace-level logs now redact all header values
// by default. Allowlist specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "X-Request-Id"
        && header != "X-Correlation-Id"
        && header != "Cache-Control"
        && header != "Accept"
        && header != "Content-Type"));

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

